            // Ensure only HTTP and HTTPS protocols are allowed
            String protocol = url.getProtocol();
            if (!"http".equalsIgnoreCase(protocol) && !"https".equalsIgnoreCase(protocol)) {
                return "Error: Only HTTP and HTTPS protocols are allowed.";
            }

