import java.net.InetAddress;
import java.net.URL;
import java.net.UnknownHostException;
import java.nio.charset.Charset;
import java.nio.charset.IllegalCharsetNameException;
import java.nio.charset.UnsupportedCharsetException;

public class UrlPreviewService {

    public String getUrlContentPreview(String urlString) {
        if (urlString == null || urlString.trim().isEmpty()) {
            return "";
        }

        try {
            URL url = new URL(urlString);

            // Validate protocol
            String protocol = url.getProtocol();
            if (!"http".equalsIgnoreCase(protocol) && !"https".equalsIgnoreCase(protocol)) {
                return "";
            }

            // Resolve host to IP and validate it's not internal
            String host = url.getHost();
            if (host == null || host.trim().isEmpty()) {
                return "";
            }

            InetAddress[] addresses = InetAddress.getAllByName(host);
            for (InetAddress addr : addresses) {
                if (addr.isAnyLocalAddress() ||
                    addr.isLoopbackAddress() ||
                    addr.isLinkLocalAddress() ||
                    addr.isSiteLocalAddress()) {
                    return "";
                }
            }

            HttpURLConnection connection = (HttpURLConnection) url.openConnection();

            // Disable redirects
            connection.setInstanceFollowRedirects(false);

            // Set timeout
            connection.setConnectTimeout(5000);
            connection.setReadTimeout(5000);

            // Set request method and headers
            connection.setRequestMethod("GET");
            connection.setRequestProperty("User-Agent", "Mozilla/5.0");

            int responseCode = connection.getResponseCode();
            if (responseCode != HttpURLConnection.HTTP_OK) {
                return "";
            }

            // Determine charset
            String contentType = connection.getContentType();
            Charset charset = Charset.forName("UTF-8");
            if (contentType != null) {
                String[] parts = contentType.split(";");
                for (String part : parts) {
                    part = part.trim();
                    if (part.toLowerCase().startsWith("charset=")) {
                        String charsetName = part.substring("charset=".length()).trim();
                        try {
                            charset = Charset.forName(charsetName);
                        } catch (IllegalCharsetNameException | UnsupportedCharsetException e) {
                            // Use default charset
                        }
                        break;
                    }
                }
            }

            // Read content
            StringBuilder content = new StringBuilder();
            try (BufferedReader reader = new BufferedReader(
                    new InputStreamReader(connection.getInputStream(), charset))) {
                char[] buffer = new char[1024];
                int bytesRead;
                int totalChars = 0;
                int maxChars = 1024;

                while ((bytesRead = reader.read(buffer)) != -1 && totalChars < maxChars) {
                    content.append(buffer, 0, Math.min(bytesRead, maxChars - totalChars));
                    totalChars += bytesRead;
                }
            }

            return content.toString();

        } catch (Exception e) {
            // Silently handle any exceptions as per requirement
            return "";
        }
    }
}
